-- Get IDs
SET @patientId = (SELECT id FROM patients WHERE email = 'john.patient@test.com' LIMIT 1);
SET @physicianId = (SELECT id FROM users WHERE role = 'admin' LIMIT 1);
SET @carePlanId = (SELECT id FROM patient_care_plans WHERE patient_id = @patientId ORDER BY id DESC LIMIT 1);

-- Create lab results with correct enum values
INSERT INTO patient_lab_results (
  patient_id, test_date, lab_name, test_results, uploaded_by, upload_method, created_at, updated_at
)
VALUES
(
  @patientId,
  DATE_SUB(NOW(), INTERVAL 30 DAY),
  'Comprehensive Metabolic Panel',
  JSON_ARRAY(
    JSON_OBJECT('testName', 'HbA1c', 'value', '8.2', 'unit', '%', 'normalRange', '4.0-5.6', 'flag', 'high'),
    JSON_OBJECT('testName', 'Fasting Glucose', 'value', '145', 'unit', 'mg/dL', 'normalRange', '70-100', 'flag', 'high'),
    JSON_OBJECT('testName', 'Total Cholesterol', 'value', '210', 'unit', 'mg/dL', 'normalRange', '<200', 'flag', 'high')
  ),
  'physician',
  'manual_entry',
  NOW(),
  NOW()
),
(
  @patientId,
  DATE_SUB(NOW(), INTERVAL 7 DAY),
  'Follow-up Glucose',
  JSON_ARRAY(
    JSON_OBJECT('testName', 'HbA1c', 'value', '7.8', 'unit', '%', 'normalRange', '4.0-5.6', 'flag', 'high'),
    JSON_OBJECT('testName', 'Fasting Glucose', 'value', '132', 'unit', 'mg/dL', 'normalRange', '70-100', 'flag', 'high')
  ),
  'physician',
  'manual_entry',
  NOW(),
  NOW()
);

-- Create check-in
INSERT INTO patient_check_ins (
  patient_id, care_plan_id, check_in_date, overall_feeling, symptoms, metrics,
  medications_taken, lifestyle_adherence, conversation_summary, alert_generated, created_at, updated_at
)
VALUES (
  @patientId,
  @carePlanId,
  DATE_SUB(NOW(), INTERVAL 3 DAY),
  7,
  JSON_ARRAY(
    JSON_OBJECT('symptom', 'Fatigue', 'severity', 3, 'notes', 'Better than last week'),
    JSON_OBJECT('symptom', 'Increased thirst', 'severity', 2)
  ),
  JSON_ARRAY(
    JSON_OBJECT('metric', 'Weight', 'value', '185', 'unit', 'lbs'),
    JSON_OBJECT('metric', 'Fasting glucose', 'value', '128', 'unit', 'mg/dL')
  ),
  JSON_ARRAY(
    JSON_OBJECT('medication', 'Metformin', 'taken', true, 'missedDoses', 0),
    JSON_OBJECT('medication', 'Lisinopril', 'taken', true, 'missedDoses', 0)
  ),
  JSON_ARRAY(
    JSON_OBJECT('activity', 'Diet', 'adherence', 85),
    JSON_OBJECT('activity', 'Exercise', 'adherence', 70)
  ),
  'Patient reports feeling better overall. Glucose levels improving with medication.',
  0,
  NOW(),
  NOW()
);

-- Create progress metrics
INSERT INTO patient_progress_metrics (
  patient_id, care_plan_id, period_start, period_end, avg_overall_feeling, avg_symptom_severity,
  medication_adherence, lifestyle_adherence, check_ins_completed, alerts_generated, created_at, updated_at
)
VALUES
(@patientId, @carePlanId, DATE_SUB(NOW(), INTERVAL 28 DAY), DATE_SUB(NOW(), INTERVAL 21 DAY), 7.2, 2.5, 90, 80, 1, 0, NOW(), NOW()),
(@patientId, @carePlanId, DATE_SUB(NOW(), INTERVAL 21 DAY), DATE_SUB(NOW(), INTERVAL 14 DAY), 7.5, 2.3, 88, 82, 1, 0, NOW(), NOW()),
(@patientId, @carePlanId, DATE_SUB(NOW(), INTERVAL 14 DAY), DATE_SUB(NOW(), INTERVAL 7 DAY), 7.8, 2.1, 92, 85, 1, 0, NOW(), NOW()),
(@patientId, @carePlanId, DATE_SUB(NOW(), INTERVAL 7 DAY), NOW(), 8.0, 1.9, 95, 88, 1, 0, NOW(), NOW());

SELECT 'Test data created successfully!' AS status,
       @patientId AS patient_id,
       @carePlanId AS care_plan_id,
       (SELECT COUNT(*) FROM patient_lab_results WHERE patient_id = @patientId) AS lab_results_count,
       (SELECT COUNT(*) FROM patient_check_ins WHERE patient_id = @patientId) AS check_ins_count,
       (SELECT COUNT(*) FROM patient_progress_metrics WHERE patient_id = @patientId) AS metrics_count;

